class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.balance = balance
    def deposit(self, amount):
        self.balance += amount
        return self.balance

acc = BankAccount('Bob', 100)
acc.deposit(50)
print(acc.balance)  # 150
